Maybe the check could be done using a [`os.Readlink`](https://pkg.go.dev/os#Readlink) instead?

```go
func useSystemd() bool {
	systemdOnce.Do(func() {
		dat, err := os.Readlink("/sbin/init")
		if err == nil {
			val := strings.TrimSuffix(string(dat), "\n")
			usesSystemd = strings.HasSuffix(val, "systemd")
		}
	})
	return usesSystemd
}
```
